def filter_players_by_distance(players, current_player, max_distance):
    visible_players = {}
    for player_id, player_data in players.items():
        if player_id != current_player['id']:
            distance = math.sqrt(
                (player_data['x'] - current_player['x']) ** 2 +
                (player_data['y'] - current_player['y']) ** 2
            )
            if distance <= max_distance:
                visible_players[player_id] = player_data
    return visible_players

